import React, { useState, useEffect } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Button,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Typography,
  Box,
  Chip,
  CircularProgress,
  Alert,
  IconButton,
  useTheme,
  useMediaQuery
} from '@mui/material';
import {
  Close,
  TrendingUp,
  TrendingDown,
  Refresh
} from '@mui/icons-material';
import dashboardService from '../../services/dashboardService';

const HistoryModal = ({ open, onClose }) => {
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));
  const [trades, setTrades] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const loadTrades = async () => {
    try {
      setLoading(true);
      setError('');
      
      console.log('🔄 Carregando trades fechados...');
      const response = await dashboardService.getClosedTrades();
      console.log('📊 Resposta da API:', response);
      
      // Processar a resposta
      let tradesData = [];
      if (response?.data && Array.isArray(response.data)) {
        tradesData = response.data;
      } else if (Array.isArray(response)) {
        tradesData = response;
      }
      
      console.log('✅ Trades processados:', tradesData);
      console.log('📊 Primeiro trade detalhado:', tradesData[0]);
      console.log('🔍 Campos ROE:', tradesData.map(t => ({ symbol: t.symbol, roe: t.roe, size: t.size })));
      setTrades(tradesData);
      
    } catch (error) {
      console.error('❌ Erro ao carregar trades:', error);
      setError('Erro ao carregar histórico de trades');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (open) {
      loadTrades();
    }
  }, [open]);

  const formatCurrency = (value) => {
    if (value === null || value === undefined) return '$0.00';
    const numValue = parseFloat(value);
    return `$${numValue.toFixed(4)}`;
  };

  const formatPercentage = (value) => {
    if (value === null || value === undefined) return '0.00%';
    const numValue = parseFloat(value);
    if (isNaN(numValue) || numValue === 0) return '0.00%';
    return `${numValue >= 0 ? '+' : ''}${numValue.toFixed(2)}%`;
  };

  const formatDateTime = (dateString) => {
    if (!dateString) return '-';
    return new Date(dateString).toLocaleString('pt-BR', {
      day: '2-digit',
      month: '2-digit',
      year: '2-digit',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const getSideColor = (side) => {
    return side === 'buy' || side === 'long' ? theme.palette.success.main : theme.palette.error.main;
  };

  const getSideIcon = (side) => {
    return side === 'buy' || side === 'long' ? <TrendingUp /> : <TrendingDown />;
  };

  return (
    <Dialog 
      open={open} 
      onClose={onClose} 
      maxWidth="lg" 
      fullWidth
      fullScreen={isMobile}
    >
      <DialogTitle sx={{ 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center',
        borderBottom: `1px solid ${theme.palette.divider}`
      }}>
        <Typography variant="h6" component="div">
          Histórico de Trades Fechados
        </Typography>
        <Box sx={{ display: 'flex', gap: 1 }}>
          <IconButton onClick={loadTrades} disabled={loading} size="small">
            <Refresh />
          </IconButton>
          <IconButton onClick={onClose} size="small">
            <Close />
          </IconButton>
        </Box>
      </DialogTitle>
      
      <DialogContent sx={{ p: 0 }}>
        {error && (
          <Alert severity="error" sx={{ m: 2 }}>
            {error}
          </Alert>
        )}
        
        {loading ? (
          <Box sx={{ display: 'flex', justifyContent: 'center', p: 4 }}>
            <CircularProgress />
          </Box>
        ) : trades.length === 0 ? (
          <Box sx={{ 
            display: 'flex', 
            flexDirection: 'column',
            alignItems: 'center', 
            justifyContent: 'center', 
            p: 4,
            minHeight: 200
          }}>
            <Typography variant="h6" color="text.secondary" gutterBottom>
              Nenhum trade fechado encontrado
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Os trades fechados aparecerão aqui após serem sincronizados
            </Typography>
          </Box>
        ) : (
          <TableContainer component={Paper} sx={{ maxHeight: '60vh' }}>
            <Table stickyHeader>
              <TableHead>
                <TableRow>
                  <TableCell><strong>Par</strong></TableCell>
                  <TableCell><strong>Lado</strong></TableCell>
                  <TableCell><strong>Tamanho</strong></TableCell>
                  <TableCell><strong>Entrada</strong></TableCell>
                  <TableCell><strong>Saída</strong></TableCell>
                  <TableCell><strong>PnL</strong></TableCell>
                  <TableCell><strong>ROE %</strong></TableCell>
                  <TableCell><strong>Fechado em</strong></TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {trades.map((trade, index) => (
                  <TableRow key={trade.id || index} hover>
                    <TableCell>
                      <Typography variant="body2" fontWeight="bold">
                        {trade.symbol}
                      </Typography>
                    </TableCell>
                    <TableCell>
                      <Chip
                        icon={getSideIcon(trade.side)}
                        label={trade.side === 'buy' || trade.side === 'long' ? 'LONG' : 'SHORT'}
                        size="small"
                        sx={{
                          bgcolor: `${getSideColor(trade.side)}20`,
                          color: getSideColor(trade.side),
                          fontWeight: 'bold'
                        }}
                      />
                    </TableCell>
                    <TableCell>
                      <Typography variant="body2">
                        {trade.size && trade.size !== '0' ? parseFloat(trade.size).toFixed(4) : '-'}
                      </Typography>
                    </TableCell>
                    <TableCell>{formatCurrency(trade.entry_price)}</TableCell>
                    <TableCell>{formatCurrency(trade.exit_price)}</TableCell>
                    <TableCell>
                      <Typography
                        sx={{
                          color: (trade.pnl || 0) >= 0 ? 'success.main' : 'error.main',
                          fontWeight: 'bold'
                        }}
                      >
                        {formatCurrency(trade.pnl)}
                      </Typography>
                    </TableCell>
                    <TableCell>
                      <Typography
                        sx={{
                          color: (trade.roe || 0) >= 0 ? 'success.main' : 'error.main',
                          fontWeight: 'bold'
                        }}
                      >
                        {formatPercentage(trade.roe)}
                      </Typography>
                    </TableCell>
                    <TableCell>
                      <Typography variant="body2">
                        {formatDateTime(trade.closed_at)}
                      </Typography>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </TableContainer>
        )}
        
        {/* Informações de debug */}
        <Box sx={{ p: 2, bgcolor: 'grey.50', borderTop: `1px solid ${theme.palette.divider}` }}>
          <Typography variant="caption" color="text.secondary">
            Debug: {trades.length} trades encontrados | 
            Status: {loading ? 'Carregando...' : 'Carregado'} |
            Última atualização: {new Date().toLocaleTimeString()}
          </Typography>
        </Box>
      </DialogContent>
      
      <DialogActions sx={{ borderTop: `1px solid ${theme.palette.divider}` }}>
        <Button onClick={onClose} variant="contained">
          Fechar
        </Button>
      </DialogActions>
    </Dialog>
  );
};

export default HistoryModal;
